SQLLite.SQL:

SELECT	ROUND(
	(
		SELECT	NVL(SUM(PAY.AMOUNT), 0)
		FROM	PAYMENTS PAY
		WHERE	PAY.ERROR_INDICATOR = 'N' AND
					PAY.ALD_DEBT_SEQ = ${param.debtSeq}
	) +
	(
		SELECT	NVL(SUM(DIV.DD_AMOUNT), 0)
		FROM	DEBT_DIVIDENDS DIV
		WHERE	DIV.DD_ALD_SEQ = ${param.debtSeq}
	),
	2
) AS "TOTAL"
FROM	DUAL
